import "./index-first.css"

function IndexFirst() {

    const carrucel = document.querySelector(".carrucel");
    const btnRight = document.querySelector(".btn-right");
    const btnLeft = document.querySelector(".btn-left");

    function scrollleft () {
        carrucel.scrollLeft -= 800
    }
    function scrollright () {
        carrucel.scrollLeft += 800
    }

    return (
        <section className="index-first">
                <div className="botones">
                    <img onClick={scrollleft} className="btn-left" src="/arrow-left.svg" alt="Flecha Izquierda" />
                    <img onClick={scrollright} className="btn-right" src="/arrow-right.svg" alt="Flecha Izquierda" />
                </div>
            <div className="carrucel-container">

                <div className="carrucel">
                    <img src="/burguer.jpg" alt="Hamburguesa" />
                    <img src="/burguer.jpg" alt="Hamburguesa" />
                    <img src="/burguer.jpg" alt="Hamburguesa" />
                    <img src="/burguer.jpg" alt="Hamburguesa" />
                </div>
            </div>
        </section>
    )
}

export default IndexFirst;
